{{(() => {
    // Calculate total from delivered and returned orders (both billable)
    const orders = ServiceBillingReport.data || [];
    const billableOrders = orders.filter(order =>
      order.billing_status === 'Billable - Delivered ✅' ||
      order.billing_status === 'Billable - Returned ↩️'
    );
    const totalUSD = billableOrders.reduce((sum, order) =>
      sum + (parseFloat(order.order_fee_usd) || 0), 0
    );

    const BGN_TO_EUR = 0.511292; // 1 USD = 0.92 EUR (approximate)

    const totalEUR = totalUSD * BGN_TO_EUR;

    return `💰 Total Amount Owed: ${totalUSD.toFixed(2)} BGN | ${totalEUR.toFixed(2)} EUR`;
  })()}}
